-- Story 2.3 — Vérification et correction des accents toniques (U+0301)
-- 1. Vérification
SELECT id, title,
  CASE WHEN content LIKE '%́%' THEN 'avec accents'
       ELSE 'SANS accents' END AS accent_status
FROM texts
ORDER BY title;

-- 2. Corrections — titres sans accents (exécuter si accent_status = 'SANS accents')
UPDATE texts SET content = 'А́нна вхо́дит в ваго́н и садится у окна́. По́езд ме́дленно е́дет. Никто́ гро́мко не говори́т. Мно́гие лю́ди смо́трят в телефо́н или чита́ют кни́гу. На сле́дующей ста́нции в ваго́н вхо́дит пожила́я же́нщина. Молодо́й челове́к сра́зу встаёт и отдаёт ей своё ме́сто. Же́нщина улыба́ется и говори́т: Спаси́бо, молодо́й челове́к. А ты ча́сто чита́ешь в тра́нспорте?' WHERE title = 'В метро';
UPDATE texts SET content = 'Са́ша идёт на рабо́ту пешко́м. Сего́дня хоро́шая пого́да. Со́лнце све́тит, не́бо голубо́е. По доро́ге он ви́дит ста́рого дру́га. Они́ здоро́ваются и немно́го разгова́ривают. Пото́м Са́ша продолжа́ет идти́. Он ду́мает о предстоя́щем дне. Рабо́та начина́ется в де́вять часо́в.' WHERE title = 'По дороге';
UPDATE texts SET content = 'Ка́ждое у́тро Ма́ша де́лает ко́фе. Она́ встаёт в семь часо́в. Снача́ла она́ идёт на ку́хню. Там она́ включа́ет кофема́шину. Пока́ ко́фе гото́вится, она́ смо́трит в окно́. На у́лице ещё темно́. Ко́фе гото́в. Ма́ша берёт ча́шку и садится за сто́л. Э́то её люби́мый моме́нт дня.' WHERE title = 'Первый кофе';
UPDATE texts SET content = 'Ива́н идёт в магази́н. Ему́ ну́жен хлеб и молоко́. В магази́не мно́го люде́й. Ива́н берёт корзи́ну. Он нахо́дит хлеб на второ́й по́лке. Молоко́ стои́т в холоди́льнике. Ива́н подхо́дит к ка́ссе. Там небольша́я о́чередь. Он пла́тит ка́ртой. Прода́вец говори́т: Спаси́бо, прихо́дите ещё.' WHERE title = 'В магазине';
UPDATE texts SET content = 'Ве́чером Оле́г прихо́дит домо́й. Он уста́л по́сле рабо́ты. Он снима́ет пальто́ и ту́фли. Пото́м он идёт на ку́хню. В холоди́льнике есть суп. Оле́г разогрева́ет суп и садится есть. По телеви́зору идёт фильм. По́сле у́жина Оле́г чита́ет кни́гу. В де́сять часо́в он ложи́тся спать.' WHERE title = 'Дома вечером';

